const express = require('express');
const app = express();
const bodyParser = require('body-parser');

app.use(bodyParser.json());

let rewards = {
    easy: 100,
    medium: 200,
    hard: 300
};

app.post('/complete-level', (req, res) => {
    const { level, score, time } = req.body;

    if (!level || !score || !time) {
        return res.status(400).json({ error: 'Missing required fields' });
    }

    let reward = 0;
    switch (level) {
        case 'easy':
            reward = Math.min(score / time, rewards.easy);
            break;
        case 'medium':
            reward = Math.min(score / time, rewards.medium);
            break;
        case 'hard':
            reward = Math.min(score / time, rewards.hard);
            break;
        default:
            return res.status(400).json({ error: 'Invalid level' });
    }

    res.json({ reward });
});

app.post('/claim-reward', (req, res) => {
    const { userId } = req.body;

    if (!userId) {
        return res.status(400).json({ error: 'Missing user ID' });
    }

    // Logic to claim and distribute rewards
    // ...

    res.json({ message: 'Reward claimed successfully' });
});

app.listen(3000, () => {
    console.log('Server is running on port 3000');
});